import{_ as s,o as a,c as i,a0 as n}from"./chunks/framework.BjpW4enL.js";const k=JSON.parse('{"title":"Known Fixes (NEXUS Runtime)","description":"","frontmatter":{},"headers":[],"relativePath":"40_Operacoes/operations/known-fixes.md","filePath":"40_Operacoes/operations/known-fixes.md","lastUpdated":1783623176000}'),o={name:"40_Operacoes/operations/known-fixes.md"};function t(r,e,l,c,d,p){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="known-fixes-nexus-runtime" tabindex="-1">Known Fixes (NEXUS Runtime) <a class="header-anchor" href="#known-fixes-nexus-runtime" aria-label="Permalink to &quot;Known Fixes (NEXUS Runtime)&quot;">​</a></h1><h2 id="missing-unique-constraint-on-abstractions" tabindex="-1">Missing Unique Constraint on <code>abstractions</code> <a class="header-anchor" href="#missing-unique-constraint-on-abstractions" aria-label="Permalink to &quot;Missing Unique Constraint on `abstractions`&quot;">​</a></h2><p>If the <code>abstractions</code> table lacks the <code>uq_abs_blob_level_chunk</code> unique constraint:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> abstractions </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ADD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> CONSTRAINT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> uq_abs_blob_level_chunk </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UNIQUE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (blob_id, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">level</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, chunk_index);</span></span></code></pre></div><p>Then TRUNCATE blobs CASCADE, clear Qdrant collections, and restart the engine.</p><h2 id="query-rs-le-de-tabela-errada-links-vs-agent-links" tabindex="-1"><code>query.rs</code> Lê de Tabela Errada (<code>links</code> vs <code>agent_links</code>) <a class="header-anchor" href="#query-rs-le-de-tabela-errada-links-vs-agent-links" aria-label="Permalink to &quot;`query.rs` Lê de Tabela Errada (`links` vs `agent_links`)&quot;">​</a></h2><p>O <code>/status</code> mostrava <code>links: 0</code> mesmo com 7487 linhas na tabela <code>agent_links</code>. A causa: <code>query.rs</code> consultava <code>FROM links</code> (tabela vazia/renomeada), enquanto o weaver escrevia em <code>agent_links</code>.</p><p><strong>Correção em <code>services/coordinator/src/query.rs</code></strong> (3 edições):</p><ul><li>PPR query: <code>FROM links l</code> → <code>FROM agent_links al</code>, colunas <code>l.relation</code> → <code>al.criteria</code>, valores <code>&#39;hilbert_bridge&#39;,&#39;supersedes&#39;</code> → <code>&#39;semantic_bridge&#39;,&#39;successor&#39;</code></li><li><code>/status</code> count: <code>FROM links</code> → <code>FROM agent_links</code></li><li><code>/pipeline-status</code> count: <code>FROM links</code> → <code>FROM agent_links</code></li></ul><h2 id="enrichment-model-errado-no-env" tabindex="-1"><code>ENRICHMENT_MODEL</code> Errado no <code>.env</code> <a class="header-anchor" href="#enrichment-model-errado-no-env" aria-label="Permalink to &quot;`ENRICHMENT_MODEL` Errado no `.env`&quot;">​</a></h2><p>O pipeline de enrich recebia 404 do Ollama em toda requisição de geração L2. A causa: <code>.env</code> forçava <code>ENRICHMENT_MODEL=qwen2.5-coder:1.5b</code>, mas o modelo carregado no Ollama é <code>qwen2.5-coder:nexus</code>.</p><p><strong>Correção em <code>.env</code></strong> (linhas 16-17):</p><div class="language-diff vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">- ENRICHMENT_MODEL=qwen2.5-coder:1.5b</span></span>\n<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">- REFLECTION_MODEL=qwen2.5-coder:1.5b</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+ ENRICHMENT_MODEL=qwen2.5-coder:nexus</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+ REFLECTION_MODEL=qwen2.5-coder:nexus</span></span></code></pre></div><p>Após corrigir, restartar o engine.</p><h2 id="qdrant-vector-schema-mismatch-2026-06-25" tabindex="-1">Qdrant Vector Schema Mismatch (2026-06-25) <a class="header-anchor" href="#qdrant-vector-schema-mismatch-2026-06-25" aria-label="Permalink to &quot;Qdrant Vector Schema Mismatch (2026-06-25)&quot;">​</a></h2><p><code>nexus_ghost</code> e <code>nexus_reflections</code> tinham vetores <strong>unnamed</strong>, mas todo código envia <code>{&quot;text_dense&quot;: vector}</code> (formato nomeado). Apenas <code>nexus_ast</code> funcionava (criada manualmente com schema correto).</p><p><strong>Sintoma</strong>: L2 rows no PostgreSQL mas 0 pontos no Qdrant.</p><p><strong>Fix</strong>: Recriar coleções com vetor nomeado <code>text_dense</code> (768d, Cosine):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DELETE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:6333/collections/nexus_ghost</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DELETE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:6333/collections/nexus_reflections</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PUT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:6333/collections/nexus_ghost</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;vectors&quot;: {&quot;text_dense&quot;: {&quot;size&quot;: 768, &quot;distance&quot;: &quot;Cosine&quot;}}, &quot;optimizers_config&quot;: {&quot;default_segment_number&quot;: 2}}&#39;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PUT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:6333/collections/nexus_reflections</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Content-Type: application/json&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;vectors&quot;: {&quot;text_dense&quot;: {&quot;size&quot;: 768, &quot;distance&quot;: &quot;Cosine&quot;}}, &quot;optimizers_config&quot;: {&quot;default_segment_number&quot;: 2}}&#39;</span></span></code></pre></div><p>Após recriar, se houver dados no PostgreSQL com <code>vector_id IS NULL</code> e nível 1/2, rodar <code>POST /enrich</code> para reprocessar.</p><h2 id="l2-phase-2-qdrant-upsert-bloqueado-por-concurrency-pile-up-2026-06-25" tabindex="-1">L2 Phase 2 (Qdrant Upsert) Bloqueado por Concurrency Pile-up (2026-06-25) <a class="header-anchor" href="#l2-phase-2-qdrant-upsert-bloqueado-por-concurrency-pile-up-2026-06-25" aria-label="Permalink to &quot;L2 Phase 2 (Qdrant Upsert) Bloqueado por Concurrency Pile-up (2026-06-25)&quot;">​</a></h2><p><strong>Problema</strong>: Múltiplas chamadas <code>run_l2_enrichment()</code> (POST /enrich + watcher + background loop) concorrentes competindo pelo semáforo Ollama (2 permits). Phase 1 (geração L2) nunca drenava → Phase 2 (Qdrant upsert) nunca executava.</p><p><strong>Sintoma</strong>: 357 L2 rows no PG, 0 em nexus_ghost. Nenhum log &quot;phase 2&quot; ou &quot;upserted&quot; após restart.</p><p><strong>Solução</strong>: <code>TRUNCATE blobs CASCADE</code> + limpar Qdrant + restart stack. Background loops sozinhos processam sem pile-up.</p><p><strong>Prevenção</strong>: Não disparar <code>POST /enrich</code> manualmente durante ingest ativa — deixar os background loops (L1 a cada 5s, L2 a cada 10s) processarem naturalmente.</p>',25)])])}const u=s(o,[["render",t]]);export{k as __pageData,u as default};
